using System;
using System.Collections;
using System.Collections.Generic;
using System.Diagnostics;
using System.Xml;
using System.Xml.XPath;

namespace MS.Internal.Xml.XPath
{
    [DebuggerDisplay("Position = {CurrentPosition}, Current = {debuggerDisplayProxy, nq}")]
    internal class XPathArrayIterator : ResettableIterator
    {
        protected IList list;
        protected int index;

        public XPathArrayIterator(IList list)
        {
            this.list = list;
        }

        public XPathArrayIterator(XPathArrayIterator it)
        {
            this.list = it.list;
            this.index = it.index;
        }

        public XPathArrayIterator(XPathNodeIterator nodeIterator)
        {
            this.list = new ArrayList();
            while (nodeIterator.MoveNext())
            {
                Debug.Assert(nodeIterator.Current != null);
                this.list.Add(nodeIterator.Current.Clone());
            }
        }

        public IList AsList
        {
            get { return this.list; }
        }

        public override XPathNodeIterator Clone()
        {
            return new XPathArrayIterator(this);
        }

        public override XPathNavigator? Current
        {
            get
            {
                Debug.Assert(index <= list.Count);

                if (index < 1)
                {
                    throw new InvalidOperationException(SR.Format(SR.Sch_EnumNotStarted, string.Empty));
                }
                return (XPathNavigator?)list[index - 1];
            }
        }

        public override int CurrentPosition { get { return index; } }
        public override int Count { get { return list.Count; } }

        public override bool MoveNext()
        {
            Debug.Assert(index <= list.Count);
            if (index == list.Count)
            {
                return false;
            }
            index++;
            return true;
        }

        public override void Reset()
        {
            index = 0;
        }

        public override IEnumerator GetEnumerator()
        {
            return list.GetEnumerator();
        }

        private object? debuggerDisplayProxy { get { return index < 1 ? null : (object)new XPathNavigator.DebuggerDisplayProxy(Current!); } }
    }
}

using System.Collections.Generic;
using System.Globalization;
using System.Linq;
using System.Text;

namespace FluentAssertions.Xml.Equivalency;

[System.Diagnostics.StackTraceHidden]
internal sealed class Node
{
    private readonly List<Node> children = [];
    private readonly string name;
    private int count;

    public static Node CreateRoot() => new(null, null);

    private Node(Node parent, string name)
    {
        Parent = parent;
        this.name = name;
    }

    public string GetXPath()
    {
        var resultBuilder = new StringBuilder();

        foreach (Node location in GetPath().Reverse())
        {
            if (location.count > 1)
            {
                resultBuilder.AppendFormat(CultureInfo.InvariantCulture, "/{0}[{1}]", location.name, location.count);
            }
            else
            {
                resultBuilder.AppendFormat(CultureInfo.InvariantCulture, "/{0}", location.name);
            }
        }

        if (resultBuilder.Length == 0)
        {
            return "/";
        }

        return resultBuilder.ToString();
    }

    private IEnumerable<Node> GetPath()
    {
        Node current = this;

        while (current.Parent is not null)
        {
            yield return current;
            current = current.Parent;
        }
    }

    public Node Parent { get; }

    public Node Push(string localName)
    {
        Node node = children.Find(e => e.name == localName)
            ?? AddChildNode(localName);

        node.count++;

        return node;
    }

    public void Pop()
    {
        children.Clear();
    }

    private Node AddChildNode(string name)
    {
        var node = new Node(this, name);
        children.Add(node);
        return node;
    }
}

