using System;
using System.Collections.Generic;
using System.Diagnostics;
using System.Globalization;
using System.Runtime.InteropServices;
using System.Text;
using Microsoft.Win32.SafeHandles;

namespace Internal.Cryptography.Pal.Windows
{
    //
    // Some CryptoApis take structure parameters that have a huge number of sub blocks attached. This convenience class lets us
    // allocate and preserve a collection of heap blocks in one single object.
    //
    internal sealed class HeapBlockRetainer : IDisposable
    {
        public HeapBlockRetainer()
        {
            _mustLive = new List<object>();
            _blocks = new List<SafeHeapAllocHandle>();
        }

        public IntPtr Alloc(int cbSize)
        {
            if (cbSize < 0)
                throw new OverflowException();
            SafeHeapAllocHandle hBlock = SafeHeapAllocHandle.Alloc(cbSize);
            _blocks.Add(hBlock);
            return hBlock.DangerousGetHandle();
        }

        public IntPtr Alloc(int howMany, int cbElement)
        {
            if (cbElement < 0 || howMany < 0)
                throw new OverflowException();

            int cbSize = checked(howMany * cbElement);
            return Alloc(cbSize);
        }

        public unsafe IntPtr AllocAsciiString(string s)
        {
            int length = Encoding.ASCII.GetByteCount(s);
            length++; // for null termination

            IntPtr pb = Alloc(length);

            var ascii = new Span<byte>((byte*)pb, length);
            Encoding.ASCII.GetBytes(s, ascii);
            ascii[^1] = 0;

            return pb;
        }

        public IntPtr AllocBytes(byte[] data)
        {
            IntPtr pData = Alloc(data.Length);
            Marshal.Copy(data, 0, pData, data.Length);
            return pData;
        }

        public void KeepAlive(object o)
        {
            _mustLive.Add(o);
        }

        public void Dispose()
        {
            if (_blocks != null)
            {
                foreach (SafeHeapAllocHandle h in _blocks)
                {
                    h.Dispose();
                }
            }
            _blocks = null!;
        }

        private readonly List<object> _mustLive;
        private List<SafeHeapAllocHandle> _blocks;
    }
}

using System;
using System.Collections.Generic;
using System.Linq;

namespace QuestPDF.Infrastructure
{
    internal sealed class PageContext : IPageContext
    {
        public bool IsInitialRenderingPhase { get; private set; } = true;
        public int DocumentLength { get; private set; }
        private List<DocumentLocation> Locations { get; } = new();

        public int CurrentDocumentId { get; private set; }
        public int CurrentPage { get; private set; }

        internal void SetDocumentId(int id)
        {
            CurrentDocumentId = id;
        }

        internal void ProceedToNextRenderingPhase()
        {
            IsInitialRenderingPhase = false;
            CurrentPage = 0;
        }

        internal void DecrementPageNumber()
        {
            CurrentPage--;
        }

        internal void IncrementPageNumber()
        {
            CurrentPage++;
            DocumentLength = Math.Max(DocumentLength, CurrentPage);
        }

        public void SetSectionPage(string name)
        {
            var location = GetLocation(name);

            if (location == null)
            {
                location = new DocumentLocation
                {
                    DocumentId = CurrentDocumentId,
                    Name = name,
                    PageStart = CurrentPage,
                    PageEnd = CurrentPage
                };

                Locations.Add(location);
            }

            if (location.PageEnd < CurrentPage)
                location.PageEnd = CurrentPage;
        }

        public DocumentLocation? GetLocation(string name)
        {
            return Locations.Find(x => x.DocumentId == CurrentDocumentId && x.Name == name);
        }

        public string GetDocumentLocationName(string locationName)
        {
            return $"{CurrentDocumentId} | {locationName}";
        }

        private List<PageElementLocation> ContentCapturedPositions { get; } = new();

        public void CaptureContentPosition(PageElementLocation location)
        {
            ContentCapturedPositions.Add(location);
        }

        public ICollection<PageElementLocation> GetContentCapturedPositions(string id)
        {
            return ContentCapturedPositions.Where(x => x.Id == id).ToList();
        }
    }
}

